@push('scripts')<script>document.querySelectorAll('[data-shop-media-preview]').forEach(function(box){var input=box.querySelector('[data-preview-input]'),target=box.querySelector('[data-preview-target]'),meta=box.querySelector('[data-preview-meta]'),clear=box.querySelector('[data-preview-clear]'),original=box.dataset.currentUrl||'',url=null;function revoke(){if(url){URL.revokeObjectURL(url);url=null;}}function restore(){revoke();target.style.backgroundImage=original?"url('"+original+"')":'';}input.addEventListener('change',function(){revoke();var file=input.files&&input.files[0];if(!file){restore();return;}url=URL.createObjectURL(file);target.style.backgroundImage="url('"+url+"')";meta.textContent=file.name+' · '+Math.ceil(file.size/1024)+' KB · '+((file.type.split('/')[1]||'—').toUpperCase().replace('JPEG','JPG'));var image=new Image();image.onload=function(){meta.textContent+=' · '+image.naturalWidth+' × '+image.naturalHeight+' px';};image.src=url;});clear.addEventListener('click',function(){input.value='';restore();});});</script>@endpush
